#!/usr/bin/env node

/**
 * Scans public/images/hero/collage/ subfolders and generates
 * the hero media manifest at src/generated/hero-media-manifest.ts.
 *
 * Usage:
 *   node scripts/scan-hero-media.js
 *   npm run hero:refresh
 *
 * Drop images (.webp, .jpg, .jpeg, .png) and videos (.mp4, .webm, .mov)
 * into the subfolders, then run this script. Alt text is auto-generated
 * from the filename (e.g., "airbnb-kitchen-setup.webp" → "Airbnb kitchen setup").
 *
 * To add a new cell: create a folder in public/images/hero/collage/ and
 * re-run this script. It auto-discovers all subfolders.
 */

const fs = require('fs');
const path = require('path');

const COLLAGE_DIR = path.join(__dirname, '..', 'public', 'images', 'hero', 'collage');
const OUTPUT_FILE = path.join(__dirname, '..', 'src', 'generated', 'hero-media-manifest.ts');

const IMAGE_EXTS = new Set(['.webp', '.jpg', '.jpeg', '.png', '.avif']);
const VIDEO_EXTS = new Set(['.mp4', '.webm', '.mov']);
const ALL_EXTS = new Set([...IMAGE_EXTS, ...VIDEO_EXTS]);

function filenameToAlt(folder, filename) {
  const name = path.parse(filename).name;
  // Replace hyphens/underscores with spaces, capitalize first letter
  const words = name.replace(/[-_]/g, ' ').replace(/\s+/g, ' ').trim();
  const label = folder.charAt(0).toUpperCase() + folder.slice(1);
  return `${label} - ${words.charAt(0).toUpperCase() + words.slice(1)}`;
}

function scanFolder(folder) {
  const dir = path.join(COLLAGE_DIR, folder);
  if (!fs.existsSync(dir)) {
    console.warn(`  ⚠ Folder not found: ${dir}`);
    return [];
  }

  const files = fs.readdirSync(dir)
    .filter(f => {
      const ext = path.extname(f).toLowerCase();
      return ALL_EXTS.has(ext) && !f.startsWith('.') && !f.includes(':');
    })
    .sort();

  return files.map(f => {
    const ext = path.extname(f).toLowerCase();
    return {
      src: `/images/hero/collage/${folder}/${f}`,
      alt: filenameToAlt(folder, f),
      type: VIDEO_EXTS.has(ext) ? 'video' : 'image',
    };
  });
}

// Auto-discover subfolders
const cells = fs.readdirSync(COLLAGE_DIR)
  .filter(f => fs.statSync(path.join(COLLAGE_DIR, f)).isDirectory())
  .sort();

console.log(`  Found ${cells.length} collage folders: ${cells.join(', ')}`);

// Scan all cells
const results = {};
let totalCount = 0;
for (const cell of cells) {
  results[cell] = scanFolder(cell);
  totalCount += results[cell].length;
  console.log(`  ${cell}/: ${results[cell].length} files`);
}

// Generate TypeScript
const outputDir = path.dirname(OUTPUT_FILE);
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

const lines = [
  '// Auto-generated by scripts/scan-hero-media.js — do not edit manually.',
  `// Last scanned: ${new Date().toISOString()}`,
  '',
  'export interface CollageMedia {',
  '  src: string;',
  '  alt: string;',
  "  type: 'image' | 'video';",
  '}',
  '',
];

for (const cell of cells) {
  const varName = `${cell}Media`;
  lines.push(`export const ${varName}: CollageMedia[] = ${JSON.stringify(results[cell], null, 2)};`);
  lines.push('');
}

lines.push(`export const CELL_NAMES: string[] = ${JSON.stringify(cells)};`);
lines.push('');
lines.push(`export const CELL_MEDIA: CollageMedia[][] = [${cells.map(c => `${c}Media`).join(', ')}];`);
lines.push('');

fs.writeFileSync(OUTPUT_FILE, lines.join('\n'));
console.log(`\n✓ Generated ${OUTPUT_FILE} (${totalCount} total media files across ${cells.length} cells)`);

if (totalCount === 0) {
  console.log('\n  No media found yet. Drop images/videos into:');
  for (const cell of cells) {
    console.log(`    public/images/hero/collage/${cell}/`);
  }
}
